sql:
SELECT source_name
FROM lpi_sources
WHERE source_id = 0;

SELECT COUNT(*) AS total_records
FROM living_planet_index
WHERE year = 2020;

SELECT contributor_name
FROM data_contributors
ORDER BY contributor_name ASC;

SELECT COUNT(*) AS total_pending_submissions
  FROM data_submissions
  WHERE submission_status = 'pending';

external_knowledge:
- The Living Planet Index (LPI) is a measure of the state of the natural world, based on the abundance of mammals, birds, fish, reptiles, and amphibians; 
- A country is a distinct national entity with its own government, occupying a particular territory; 
- The most recent LPI value refers to the latest available data, which can be used to understand the current state of the environment in various countries.

sql:
SELECT publication_title
FROM lpi_publications
WHERE publication_year = 2016;

SELECT entity_name
FROM entities
WHERE area_km2 = (SELECT MAX(area_km2) FROM entities);

SELECT lpi_value
FROM living_planet_index
WHERE year = 1970;
